inputs.script:
const c=(v)=>{const t=String(v==null?'':v).trim();return /^\{[a-zA-Z0-9_]+\}$/.test(t)?'':t;};
let max=parseInt(c(arg0),10);if(!Number.isFinite(max)||max<1)max=20;if(max>50)max=50;
const norm=(v)=>(v||'').replace(/\u00a0/g,' ').replace(/\s+/g,' ').trim();
const PREFIX='Open control menu for post by ';
const cleanUrl=(a)=>{if(!a)return '';try{const u=new URL(a.getAttribute('href'),location.origin);return u.origin+u.pathname;}catch(e){return a.getAttribute('href')||'';}};
const cardOf=(btn)=>{let card=btn;for(let i=0;i<18;i++){if(!card.parentElement)break;card=card.parentElement;if(card.querySelector('[data-testid="expandable-text-box"]')&&card.querySelector('button[aria-label="Comment"]'))return card;}return null;};
const wordCount=(txt,re)=>{const m=(txt||'').match(re);return m?m[1].replace(/,/g,''):null;};
const bareAfterBox=(card,box)=>{const nums=[];card.querySelectorAll('*').forEach((e)=>{if(e.childElementCount===0){const t=(e.innerText||'').trim();if(/^[\d,]{1,7}$/.test(t)){if(!box||((box.compareDocumentPosition(e)&Node.DOCUMENT_POSITION_FOLLOWING)&&!box.contains(e)))nums.push(t.replace(/,/g,''));}}});return nums;};
const btns=[...document.querySelectorAll('button[aria-label^="Open control menu for post by "]')];
const out=[];const seen=new Set();
for(const btn of btns){
  const card=cardOf(btn);if(!card||seen.has(card))continue;
  const box=card.querySelector('[data-testid="expandable-text-box"]');
  const text=norm(box?box.innerText:'');if(!text)continue;seen.add(card);
  const author=norm((btn.getAttribute('aria-label')||'').slice(PREFIX.length));
  const links=[...card.querySelectorAll('a[href*="/in/"],a[href*="/company/"]')];
  let link=links.find((a)=>norm(a.innerText)===author);
  if(!link)link=links.find((a)=>{const t=norm(a.innerText);return t&&(author.indexOf(t)>=0||t.indexOf(author)>=0);});
  if(!link)link=links[0];
  const cardText=norm(card.innerText||'');const bare=bareAfterBox(card,box);
  const reactions=wordCount(cardText,/([\d,]+)\s*reactions?/i)||bare[0]||'0';
  const comments=wordCount(cardText,/([\d,]+)\s*comments?/i)||bare[1]||'0';
  const reposts=wordCount(cardText,/([\d,]+)\s*reposts?/i)||bare[2]||'0';
  out.push({author:author,author_url:cleanUrl(link),text:text,reactions:reactions,comments:comments,reposts:reposts});
  if(out.length>=max)break;
}
return out;
